OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page



//   if(IsProject()==0)   int textMode=0;

   int textMode=0;



   LoadGroup("Cursors2.grp");

   SetCursor(0);



//#############################################################################

   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   int txtHotSpotOn=0;

   int playStatus=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

//############################################################################



   int motyle[6];

   int time[6];

   int pom;

   int stat_slonko=0;

   int krowki=0;

   int motylki=0;

   int helpTime=0;



   Sound_Holder.PlayDSound(0);

   SetTextMode();



   FadeScreen(1,1000);

   Sprite_Holder.SynchronizeTimers();

   SetTimer(500);

}





void OnClosePage(void)

{

	// Add your close page handler code here



}





void SetTextMode()

{

   motylki=0;

   if(textMode==0)

   {

      int xx;

      int yy;

      int deep;



      DisableScreen();

      Sprite_Holder.GetPosition(0,&xx,&yy,&deep);

      Sprite_Holder.GotoXY(0,xx-200,yy-580);

      Sprite_Holder.GetPosition(1,&xx,&yy,&deep);

      Sprite_Holder.GotoXY(1,xx+200,yy-580);

      Sprite_Holder.GetPosition(2,&xx,&yy,&deep);

      Sprite_Holder.GotoXY(2,xx-20,yy-580);

      Sprite_Holder.GetPosition(3,&xx,&yy,&deep);

      Sprite_Holder.GotoXY(3,xx+50,yy-580);

      Sprite_Holder.GetPosition(4,&xx,&yy,&deep);

      Sprite_Holder.GotoXY(4,xx-20,yy-580);

      EnableScreen();

      ShowBuffer();



      Sprite_Holder.SynchronizeTimers();

      Sprite_Holder.EnableTimers();



      playStatus=0;



      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(0,0,0,0);

      Sprite_Holder.CompEnableDrag();

   }

   else

   {

      motyle[0]=0;

      motyle[1]=0;

      motyle[2]=0;

      motyle[3]=0;

      motyle[4]=0;



      Sprite_Holder.DisableTimers();



      playStatus=1;



      Transparent_Video_Holder.Stop();



      Sound_Holder.SetPlayDSoundParameters(0,-1000,0,0);

      Sound_Holder.PlayDSound(1);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

      Sprite_Holder.CompDisableDrag();

   }

}







VOID HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   if(textMode) return;



   switch (rectID)

   {

      case 0:

         krowki=0;

         Transparent_Video_Holder.Play(0,0);

         break;

      case 1:

         krowki=0;

         if(stat_slonko==0)

         {

            Transparent_Video_Holder.Play(2,0);

            stat_slonko=255;

         }

         else

         {

            Transparent_Video_Holder.Play(3,0);

            stat_slonko=0;

         }

         break; 

      case 3: 

         krowki=0;

         Transparent_Video_Holder.Play(5,0);

         break;

      case 4:

         if(krowki!=0)   break;

         Transparent_Video_Holder.Play(1,0);

      default:

         return;

   }

   ResetMotyle();

}



VOID Transparent_Video_Holder.MouseClickOnDown(int videoID)

{

   if(textMode) return;



   if(videoID==4)  krowki=1;

   Transparent_Video_Holder.Play(videoID,0);

}





VOID Sprite_Holder.InPlace(int spriteID,int x,int y)

{

   if(textMode) return;

   int xx;

   switch (spriteID)

   {

      case 0:

         xx=Random(100,640);

         Sprite_Holder.MoveTo(0,xx,480);

         Sprite_Holder.GotoXY(0,xx-200,-100);

         break;

      case 1:

         xx=Random(0,400);

         Sprite_Holder.MoveTo(1,xx,480);

         Sprite_Holder.GotoXY(1,xx+200,-100);

         break;

      case 2:

         xx=Random(0,550);

         Sprite_Holder.MoveTo(2,xx,480);

         Sprite_Holder.GotoXY(2,xx+Random(0,50),-100);

         break;

      case 3:

         xx=Random(0,500);

         Sprite_Holder.MoveTo(3,xx,480);

         Sprite_Holder.GotoXY(3,xx+Random(0,100),-100);

         break;

      case 4:

         xx=Random(0,600);

         Sprite_Holder.MoveTo(4,xx,480);

         Sprite_Holder.GotoXY(4,xx+Random(0,20),-100);

         break;

   }

}



void ResetMotyle(void)

{

   if(motylki==0)   return;

   motylki=0;

   int xx;

   int yy;

   int deep;



   DisableScreen();

//   Sprite_Holder.SetDeep(0,4);

//   Sprite_Holder.SetDeep(1,4);

//   Sprite_Holder.SetDeep(2,4);

//   Sprite_Holder.SetDeep(3,4);

//   Sprite_Holder.SetDeep(4,4);



   xx=Random(100,640);

   Sprite_Holder.MoveTo(0,xx,480);

   Sprite_Holder.GotoXY(0,xx-200,-100);

   xx=Random(0,400);

   Sprite_Holder.MoveTo(1,xx,480);

   Sprite_Holder.GotoXY(1,xx+200,-100);

   xx=Random(0,550);

   Sprite_Holder.MoveTo(2,xx,480);

   Sprite_Holder.GotoXY(2,xx+Random(0,50),-100);

   xx=Random(0,500);

   Sprite_Holder.MoveTo(3,xx,480);

   Sprite_Holder.GotoXY(3,xx+Random(0,100),-100);

   xx=Random(0,600);

   Sprite_Holder.MoveTo(4,xx,480);

   Sprite_Holder.GotoXY(4,xx+Random(0,20),-100);



   Sprite_Holder.SynchronizeTimers();

   Sprite_Holder.EnableTimers();

   motyle[0]=0;

   motyle[1]=0;

   motyle[2]=0;

   motyle[3]=0;

   motyle[4]=0;



   Sprite_Holder.ShowSprite(0);

   Sprite_Holder.ShowSprite(1);

   Sprite_Holder.ShowSprite(2);

   Sprite_Holder.ShowSprite(3);

   Sprite_Holder.ShowSprite(4);



   EnableScreen();

   ShowBuffer();

}



void Transparent_Video_Holder.TheEnd(int videoID)

{

   if(videoID==4)   krowki=0;

   if(videoID==6 && textMode==0)

      ResetMotyle();

}







