void OnTimer(void)

{

        //Add your command handler code here

/*   if(helpTime>=0)

   {

      helpTime++;

      if(helpTime>10)

      {

         Sound_Holder.PlayDSound(7);

         helpTime=-1;

      }      

   }

*/   int xx=0;

   while(xx<5)

   {

      if(motyle[xx])

      {

         time[xx]--;

         if(time[xx]==0)

         {

            Sound_Holder.PlayDSound(6);

            motyle[xx]=0;

            int m_yy;

            int m_xx;

            int m_deep;

            Sprite_Holder.ShowSprite(xx);

            Sprite_Holder.GetPosition(xx,&m_xx,&m_yy,&m_deep);

            switch(xx)

            {

               case 0:

                  Sprite_Holder.GotoXY(0,m_xx-200,m_yy-580);

                  break;

               case 1:

                  Sprite_Holder.GotoXY(1,m_xx+200,m_yy-580);

                  break;

               case 2:

                  Sprite_Holder.GotoXY(2,m_xx-20,m_yy-580);

                  break;

               case 3:

                  Sprite_Holder.GotoXY(3,m_xx+50,m_yy-580);

                  break;

               case 4:

                  Sprite_Holder.GotoXY(4,m_xx-20,m_yy-580);

                  break;

            }

         }

      }

      xx++;

   }

}





void Sprite_Holder.MouseDrop(int spriteID,int left,int top,int right,int bottom)

{

   int res;

   int xx;

   int yy;

   int deep;

   HotSpot_Holder.PointInHotSpot(6,left+((right-left)/2),top+((bottom-top)/2),&res);

   if(res)

   {

      if(motyle[spriteID]==0)

      {

         Sprite_Holder.HideSprite(spriteID);

         motyle[spriteID]=1;

         switch(spriteID)   //czasy po ile motylki siedza w koszu

         {   

            case 0: 

               time[spriteID]=5;

               break;

            case 1: 

               time[spriteID]=10;

               break;

            case 2: 

               time[spriteID]=8;

               break;

            case 3: 

               time[spriteID]=15;

               break;

            case 4: 

               time[spriteID]=4;

               break;

         }

      }

      xx=0;

      while(xx<5)

      {

         if(motyle[xx]==0)   break;

         xx++;

      }

      if(xx<5)

         Sound_Holder.PlayDSound(2);

      else

      {

         xx=0;

         while(xx<5)

         {

            motyle[xx]=0;

            xx++;

         }

         Transparent_Video_Holder.Play(6,0);

         motylki=1;

         Sprite_Holder.HideSprite(0);

         Sprite_Holder.HideSprite(1);

         Sprite_Holder.HideSprite(2);

         Sprite_Holder.HideSprite(3);

         Sprite_Holder.HideSprite(4);

      }

   }

   else

   {

      motyle[spriteID]=0;

      Sound_Holder.PlayDSound(3);

      switch(spriteID)

      {

         case 0:

            Sprite_Holder.GetPosition(0,&xx,&yy,&deep);

            Sprite_Holder.GotoXY(0,xx-200,yy-580);

            break;

         case 1:

            Sprite_Holder.GetPosition(1,&xx,&yy,&deep);

            Sprite_Holder.GotoXY(1,xx+200,yy-580);

            break;

         case 2:

            Sprite_Holder.GetPosition(2,&xx,&yy,&deep);

            Sprite_Holder.GotoXY(2,xx-20,yy-580);

            break;

         case 3:

            Sprite_Holder.GetPosition(3,&xx,&yy,&deep);

            Sprite_Holder.GotoXY(3,xx+50,yy-580);

            break;

         case 4:

            Sprite_Holder.GetPosition(4,&xx,&yy,&deep);

            Sprite_Holder.GotoXY(4,xx-20,yy-580);

            break;

      }

   }

}





